action.command:
cat > /tmp/oxc_repro_enum_comment.sh <<'EOF'
#!/usr/bin/env bash
repo=/workspace/oxc
tmpfile=$(mktemp /tmp/oxc-enum-comment-XXXXXX.tsx)
trap 'rm -f "$tmpfile"' EXIT
cat > "$tmpfile" <<'TSX'
type Foo = {
  // Type comment
};

interface Bar {
  // Interface comment
}

enum Baz {
  // Enum comment, this will break after formatting
}
TSX
expected=$(cat <<'TSX'
type Foo = {
  // Type comment
};

interface Bar {
  // Interface comment
}

enum Baz {
  // Enum comment, this will break after formatting
}
TSX
)
(
  cd "$repo" && cargo run -q -p oxfmt -- "$tmpfile" >/tmp/oxc-repro-stdout.txt 2>/tmp/oxc-repro-stderr.txt
)
actual=$(cat "$tmpfile")
if [ "$actual" != "$expected" ]; then
  echo 'Formatted output did not match expected Prettier-compatible output.'
  echo '--- actual ---'
  printf '%s\n' "$actual"
  echo '--- expected ---'
  printf '%s\n' "$expected"
  echo '--- oxfmt stdout ---'
  cat /tmp/oxc-repro-stdout.txt
  echo '--- oxfmt stderr ---'
  cat /tmp/oxc-repro-stderr.txt
  exit 1
fi
printf '%s\n' 'Reproduction passed: output matches expected.'
EOF
chmod +x /tmp/oxc_repro_enum_comment.sh
/tmp/oxc_repro_enum_comment.sh

