#!/usr/bin/env bash
repo=/workspace/oxc
run_case() {
  name=$1
  input=$2
  expected=$3
  tmpfile=$(mktemp "/tmp/oxc-${name}-XXXXXX.ts")
  printf '%s' "$input" > "$tmpfile"
  (cd "$repo" && cargo run -q -p oxfmt --no-default-features -- "$tmpfile" >/tmp/oxc-edge-stdout.txt 2>/tmp/oxc-edge-stderr.txt)
  status=$?
  if [ "$status" -ne 0 ]; then
    echo "[$name] oxfmt failed with exit $status"
    cat /tmp/oxc-edge-stdout.txt
    cat /tmp/oxc-edge-stderr.txt
    rm -f "$tmpfile"
    exit "$status"
  fi
  actual=$(cat "$tmpfile")
  rm -f "$tmpfile"
  if [ "$actual" != "$expected" ]; then
    echo "[$name] output mismatch"
    echo '--- actual ---'
    printf '%s\n' "$actual"
    echo '--- expected ---'
    printf '%s\n' "$expected"
    exit 1
  fi
  echo "[$name] passed"
}
run_case "empty-enum" 'enum Empty {}' 'enum Empty {}'
run_case "line-comments" 'enum Baz {
// a
// b
}' 'enum Baz {
  // a
  // b
}'
run_case "block-comment" 'enum Baz {/* block */}' 'enum Baz {
  /* block */
}'
run_case "declare-const" 'declare const enum Baz {
// a
}' 'declare const enum Baz {
  // a
}'
EOF
chmod +x /tmp/oxc_enum_comment_edges.sh
bash /tmp/oxc_enum_comment_edges.sh

